class Solution:
    def minCostGoodCaption(self, caption):
        n = len(caption)
        if n < 3:
            return ''
        vals = [ord(c) - 97 for c in caption]
        INF = float('inf')
        dp = [INF] * (n + 1)
        best_str = [None] * (n + 1)
        dp[n] = 0
        best_str[n] = ''
        for i in range(n - 1, -1, -1):
            best_cost = INF
            best_choice = None
            for L in range(3, n - i + 1):
                if dp[i + L] == INF:
                    continue
                block = vals[i:i + L]
                for letter in range(26):
                    cost = sum(abs(v - letter) for v in block)
                    total = cost + dp[i + L]
                    if total < best_cost:
                        best_cost = total
                        best_choice = (L, letter)
                    elif total == best_cost and best_choice is not None:
                        cand = chr(letter + 97) * L + best_str[i + L]
                        cur = chr(best_choice[1] + 97) * best_choice[0] + best_str[i + best_choice[0]]
                        if cand < cur:
                            best_choice = (L, letter)
            dp[i] = best_cost
            if best_choice is None:
                best_str[i] = None
            else:
                L, letter = best_choice
                best_str[i] = chr(letter + 97) * L + best_str[i + L]
        return best_str[0] if best_str[0] is not None else ''

