var minCostGoodCaption = function(caption) {
    const n = caption.length;
    if (n < 3) return '';
    const vals = [];
    for (let i = 0; i < n; i++) vals.push(caption.charCodeAt(i) - 97);
    const INF = Infinity;
    const dp = new Array(n + 1).fill(INF);
    const bestStr = new Array(n + 1).fill(null);
    dp[n] = 0;
    bestStr[n] = '';
    for (let i = n - 1; i >= 0; i--) {
        let bestCost = INF, bestL = -1, bestLetter = -1;
        for (const L of [3, 4, 5]) {
            if (i + L > n || dp[i + L] === INF) continue;
            const block = vals.slice(i, i + L);
            const s = block.slice().sort((a, b) => a - b);
            const letterVal = (L % 2 === 1) ? s[Math.floor(L / 2)] : s[Math.floor(L / 2) - 1];
            let cost = 0;
            for (const v of block) cost += Math.abs(v - letterVal);
            const total = cost + dp[i + L];
            if (total < bestCost) {
                bestCost = total; bestL = L; bestLetter = letterVal;
            } else if (total === bestCost && bestL !== -1) {
                const candidate = String.fromCharCode(letterVal + 97).repeat(L) + bestStr[i + L];
                const existing = String.fromCharCode(bestLetter + 97).repeat(bestL) + bestStr[i + bestL];
                if (candidate < existing) { bestL = L; bestLetter = letterVal; }
            }
        }
        dp[i] = bestCost;
        if (bestL === -1) {
            bestStr[i] = null;
        } else {
            bestStr[i] = String.fromCharCode(bestLetter + 97).repeat(bestL) + bestStr[i + bestL];
        }
    }
    return bestStr[0] !== null ? bestStr[0] : '';
};
